from dataclasses import dataclass, field
from difflib import SequenceMatcher

@dataclass
class Candidate:
    id: str
    label: str           # display name
    detail: str          # disambiguating detail (type, date, owner, etc.)
    score: float = 1.0   # higher = better match

def find_candidates(
    reference: str,
    entities: list[dict],   # {"id": ..., "label": ..., "detail": ...}
    max_results: int = 5,
    min_score: float = 0.4,
) -> list[Candidate]:
    """Fuzzy-match reference against entity labels; return ranked candidates."""
    scored = []
    ref_lower = reference.lower()

    for entity in entities:
        label = entity["label"]
        # Exact match gets top score
        if label.lower() == ref_lower:
            score = 1.0
        else:
            score = SequenceMatcher(None, ref_lower, label.lower()).ratio()
        if score >= min_score:
            scored.append(Candidate(
                id=entity["id"],
                label=label,
                detail=entity.get("detail", ""),
                score=score,
            ))

    return sorted(scored, key=lambda c: c.score, reverse=True)[:max_results]

def rank_candidates(
    candidates: list[Candidate],
    recent_entity_ids: list[str],   # IDs mentioned in recent context, newest first
    usage_counts: dict[str, int],   # how often each entity appears in this session
) -> list[Candidate]:
    recency_index = {eid: i for i, eid in enumerate(recent_entity_ids)}
    max_usage = max(usage_counts.values(), default=1) or 1

    def composite_score(c: Candidate) -> float:
        fuzzy  = c.score                                    # 0-1
        # Recency: most recent = 1.0, older = decay
        recency_rank = recency_index.get(c.id, len(recent_entity_ids))
        recency = 1.0 / (1.0 + recency_rank * 0.3)
        # Usage frequency normalised to 0-1
        freq = usage_counts.get(c.id, 0) / max_usage

        return fuzzy * 0.5 + recency * 0.35 + freq * 0.15

    return sorted(candidates, key=composite_score, reverse=True)

import asyncio
import uuid

DISAMBIGUATE_TOOL = {
    "name": "disambiguate",
    "description": (
        "Present the human with a list of candidate matches when a reference is ambiguous. "
        "Use this only when multiple candidates are plausible and the choice affects the action. "
        "Do not use it when you can infer the correct entity from context with high confidence."
    ),
    "input_schema": {
        "type": "object",
        "properties": {
            "reference": {
                "type": "string",
                "description": "The ambiguous term or phrase the user wrote.",
            },
            "context": {
                "type": "string",
                "description": "Brief explanation of why it is ambiguous.",
            },
            "candidates": {
                "type": "array",
                "maxItems": 4,
                "items": {
                    "type": "object",
                    "properties": {
                        "id":     {"type": "string"},
                        "label":  {"type": "string"},
                        "detail": {"type": "string"},
                    },
                    "required": ["id", "label"],
                },
                "description": "Ranked list of up to 4 candidates. Best match first.",
            },
        },
        "required": ["reference", "candidates"],
    },
}

_pending_disambig: dict[str, asyncio.Event] = {}
_disambig_answers: dict[str, str | None] = {}

async def handle_disambiguate(params: dict, timeout: float = 300.0) -> str:
    req_id = str(uuid.uuid4())
    event = asyncio.Event()
    _pending_disambig[req_id] = event
    _disambig_answers[req_id] = None

    candidates = params.get("candidates", [])
    reference  = params.get("reference", "")
    context    = params.get("context", "")

    # Surface to the human (in prod: push to dashboard / chat)
    print(f"[DISAMBIGUATE] '{reference}' is ambiguous. {context}")
    for i, c in enumerate(candidates, 1):
        detail = f" ({c['detail']})" if c.get("detail") else ""
        print(f"  {i}. {c['label']}{detail} [id={c['id']}]")
    print(f"  Submit choice at: POST /disambiguations/{req_id}/choose")

    try:
        await asyncio.wait_for(event.wait(), timeout=timeout)
        chosen_id = _disambig_answers.get(req_id)
        if chosen_id is None:
            # "none of these"
            return f"[DISAMBIGUATION] None of the candidates matched. Please rephrase."
        match = next((c for c in candidates if c["id"] == chosen_id), None)
        if match:
            return f"resolved:{chosen_id}|{match['label']}"
        return f"[DISAMBIGUATION ERROR] Unknown candidate id: {chosen_id}"
    except asyncio.TimeoutError:
        # Use the top-ranked candidate as default
        if candidates:
            top = candidates[0]
            return f"[TIMEOUT] Using best match: {top['label']} (id={top['id']})"
        return "[TIMEOUT] No candidates; cannot resolve."
    finally:
        _pending_disambig.pop(req_id, None)
        _disambig_answers.pop(req_id, None)

from fastapi import FastAPI, HTTPException
from pydantic import BaseModel
from typing import Optional

app = FastAPI()

class ChoiceBody(BaseModel):
    candidate_id: Optional[str] = None   # None = "none of these"

@app.post("/disambiguations/{request_id}/choose")
def choose_candidate(request_id: str, body: ChoiceBody):
    event = _pending_disambig.get(request_id)
    if not event:
        raise HTTPException(404, "Disambiguation request not found or already resolved")
    _disambig_answers[request_id] = body.candidate_id
    event.set()
    return {
        "status": "resolved",
        "chosen_id": body.candidate_id,
    }

SCOPE_DISAMBIGUATE_TOOL = {
